import React, { useState } from 'react';
import {
  View,
  StyleSheet,
  ScrollView,
  KeyboardAvoidingView,
  Platform,
} from 'react-native';
import { TextInput, Button, Text, SegmentedButtons } from 'react-native-paper';

export default function RegisterScreen({ navigation }) {
  const [userType, setUserType] = useState('buyer');
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    password: '',
    confirmPassword: '',
    farmName: '', // For farmers
    farmLocation: '', // For farmers
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const updateFormData = (key, value) => {
    setFormData(prev => ({ ...prev, [key]: value }));
  };

  const handleRegister = async () => {
    setError('');

    // Validation
    if (!formData.name || !formData.email || !formData.phone || !formData.password) {
      setError('Please fill in all required fields');
      return;
    }

    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match');
      return;
    }

    if (userType === 'farmer' && (!formData.farmName || !formData.farmLocation)) {
      setError('Please provide farm details');
      return;
    }

    setLoading(true);
    try {
      // Import the service
      const { registerUser } = require('../services/api');

      const payload = {
        name: formData.name,
        email: formData.email,
        password: formData.password,
        role: userType === 'farmer' ? 'trainer' : 'student' // Map roles
      };

      await registerUser(payload);

      alert('Registration successful! Please login.');
      navigation.navigate('Login');
    } catch (err) {
      setError(err.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <KeyboardAvoidingView
      behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
      style={styles.container}
    >
      <ScrollView contentContainerStyle={styles.scrollContainer}>
        <Text style={styles.title}>Create Account</Text>

        <SegmentedButtons
          value={userType}
          onValueChange={setUserType}
          buttons={[
            { value: 'buyer', label: 'Buyer', icon: 'cart' },
            { value: 'farmer', label: 'Farmer', icon: 'sprout' },
          ]}
          style={styles.segmentedButtons}
        />

        <TextInput
          label="Full Name"
          value={formData.name}
          onChangeText={(text) => updateFormData('name', text)}
          mode="outlined"
          style={styles.input}
          left={<TextInput.Icon icon="account" />}
        />

        <TextInput
          label="Email"
          value={formData.email}
          onChangeText={(text) => updateFormData('email', text)}
          mode="outlined"
          keyboardType="email-address"
          autoCapitalize="none"
          style={styles.input}
          left={<TextInput.Icon icon="email" />}
        />

        <TextInput
          label="Phone Number"
          value={formData.phone}
          onChangeText={(text) => updateFormData('phone', text)}
          mode="outlined"
          keyboardType="phone-pad"
          style={styles.input}
          left={<TextInput.Icon icon="phone" />}
        />

        {userType === 'farmer' && (
          <>
            <TextInput
              label="Farm Name"
              value={formData.farmName}
              onChangeText={(text) => updateFormData('farmName', text)}
              mode="outlined"
              style={styles.input}
              left={<TextInput.Icon icon="barn" />}
            />

            <TextInput
              label="Farm Location"
              value={formData.farmLocation}
              onChangeText={(text) => updateFormData('farmLocation', text)}
              mode="outlined"
              style={styles.input}
              left={<TextInput.Icon icon="map-marker" />}
            />
          </>
        )}

        <TextInput
          label="Password"
          value={formData.password}
          onChangeText={(text) => updateFormData('password', text)}
          mode="outlined"
          secureTextEntry
          style={styles.input}
          left={<TextInput.Icon icon="lock" />}
        />

        <TextInput
          label="Confirm Password"
          value={formData.confirmPassword}
          onChangeText={(text) => updateFormData('confirmPassword', text)}
          mode="outlined"
          secureTextEntry
          style={styles.input}
          left={<TextInput.Icon icon="lock-check" />}
        />

        {error ? <Text style={styles.errorText}>{error}</Text> : null}

        <Button
          mode="contained"
          onPress={handleRegister}
          loading={loading}
          disabled={loading}
          style={styles.button}
          buttonColor="#2E7D32"
        >
          Register
        </Button>

        <Button
          mode="text"
          onPress={() => navigation.navigate('Login')}
          style={styles.loginButton}
        >
          Already have an account? Login
        </Button>
      </ScrollView>
    </KeyboardAvoidingView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#fff',
    alignItems: 'center',
    justifyContent: 'center',
  },
  scrollContainer: {
    padding: 20,
    width: '100%',
    maxWidth: 500, // Limit width on web
  },
  title: {
    fontSize: 28,
    fontWeight: 'bold',
    color: '#2E7D32',
    marginBottom: 20,
    textAlign: 'center',
  },
  segmentedButtons: {
    marginBottom: 20,
  },
  input: {
    marginBottom: 15,
  },
  button: {
    marginTop: 10,
    paddingVertical: 6,
  },
  loginButton: {
    marginTop: 15,
  },
  errorText: {
    color: '#d32f2f',
    marginBottom: 10,
    textAlign: 'center',
  },
});
